import { json } from '@sveltejs/kit';
import type { RequestHandler } from './$types';
import { db } from '$lib/server/db';
import * as schema from '$lib/server/db/schema';

/**
 * External Audit Ingestion API
 * Allows sidecar agents and external services to report events to the centralized Audit Vault.
 */
export const POST: RequestHandler = async ({ request, locals }) => {
    // Identity is resolved via X-API-Key or JWT in hooks.server.ts
    if (!locals.user) {
        return json({ error: 'Unauthorized' }, { status: 401 });
    }

    try {
        const body = await request.json();
        const { event, metadata, resourceId } = body;

        if (!event) {
            return json({ error: 'Missing mandatory "event" field' }, { status: 400 });
        }

        // Standardize event naming
        const normalizedEvent = event.trim().toUpperCase();

        // Enforce high-signal audit structure
        const auditEntry = {
            userId: locals.user.id,
            event: normalizedEvent,
            timestamp: new Date(),
            metadata: JSON.stringify({
                ... (typeof metadata === 'object' ? metadata : { raw: metadata }),
                resourceId: resourceId || undefined,
                ingestionSource: 'EXTERNAL_API_GATEWAY'
            })
        };

        await db.insert(schema.auditLogs).values(auditEntry);

        return json({ 
            success: true, 
            auditId: (auditEntry as any).id // id is auto-generated by DB, this is just for feedback if needed
        });
    } catch (err: any) {
        console.error('[API] Audit Ingestion Failure:', err);
        return json({ error: 'Failed to ingest audit event' }, { status: 500 });
    }
};
